mapper.select:
/* adm-master-storexct-sql-oracle.xml - selectStorexct */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT A.OWKEY , OW.OWNM , B.CTKEY , CT.CTNM , B.STOREKEY , A.STORENM , TMST.ARR_TIME , A.ZIPCD , A.ADDR1 , A.ADDR2 , A.DELYN , B.NEWYN , A.OWNM , A.REGNO , A.TEL1 , A.TEL2 , COALESCE(B.CLOSDATE, '29991231235959') AS CLOSDATE , B.INSERTDATE , B.UPDATEDATE , B.INSERTURKEY , B.UPDATEURKEY , TMST.ARRTIMEAPPLYDATE AS ARR_TIME_APPLYDATE , TMST.SPCL01YN , TMST.SPCL02YN , TMST.SPCL03YN , TMST.SPCL04YN , TMST.SPCL05YN , TMST.SPCL06YN , TMST.SPCLSTOREYN , TMST.DOCKKEY , TMST.DCKEY , B.ICGRPKEY , C.ICGRPNM , B.SCMCK , B.SCMURKEY FROM TADMIN_MST_STORE A INNER JOIN TADMIN_MST_STOREXCT B ON A.STOREKEY = B.STOREKEY AND A.OWKEY = B.OWKEY LEFT OUTER JOIN TADMIN_MST_ICGR C ON B.ICGRPKEY = C.ICGRPKEY AND B.OWKEY = C.OWKEY LEFT OUTER JOIN TADMIN_MST_OW OW ON A.OWKEY = OW.OWKEY LEFT OUTER JOIN TADMIN_MST_CT CT ON B.CTKEY = CT.CTKEY LEFT OUTER JOIN TT_MST_STOREXCT TMST ON B.CTKEY = TMST.CTKEY AND B.STOREKEY = TMST.STORE_KEY AND B.RNDKEY = TMST.DCKEY
AND #{SEARCH_CONDITION}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY B.UPDATEDATE DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

mapper.insert:
/* adm-master-storexct-sql-oracle.xml - insertTAdminMstStorexct */
INSERT INTO TADMIN_MST_STOREXCT
(
	  UPDATEURKEY
	 ,UPDATEDATE
	 ,INSERTURKEY
	 ,INSERTDATE
	 ,CTKEY
	 ,STOREKEY
	 ,NEWYN
	 ,RNDKEY
	 ,ICGRPKEY
 ) VALUES (
	  #{surkey}
	 ,#{sysdate}
	 ,#{surkey}
	 ,#{sysdate}
	 ,#{ctkey}
	 ,#{storekey}
	 ,'Y'
	 ,#{rndkey}
	 ,#{icgrpkey}
 )

mapper.update:
/* adm-master-storexct-sql-oracle.xml - updateTAdminMstStorexct */
UPDATE TADMIN_MST_STOREXCT
SET   ARRTIME = #{arrtime}
	, NEWYN = #{newyn} 
	, ARRTIMEAPPLYDATE = #{arrtimeapplydate}
	, CLOSDATE = #{closdate}
	, UPDATEURKEY = #{surkey}
	, UPDATEDATE = #{sysdate}
WHERE CTKEY = #{ctkey}
AND   STOREKEY = #{storeKey}

	AND	  OWKEY = #{owkey}

/* adm-master-storexct-sql-oracle.xml - updateTTMstStorexct */
UPDATE TT_MST_STOREXCT
SET   ARR_TIME = #{arrTime}
	, UPDATEURKEY = #{surkey}
	, UPDATEDATE = #{sysdate}
WHERE CTKEY = #{ctkey}
  AND STORE_KEY = #{storeKey}

	AND	  OWKEY = #{owkey}
